/// BTModalSheet — static helper that wraps [BTModal] in [showDialog].
///
/// Internal-only file (re-exported via `modal.dart`). Designers / app
/// consumers should call [BTModalSheet.show] rather than building the
/// dialog route by hand.
library;

import 'package:btech_ui/src/components/organisms/modal/modal.widget.dart';
import 'package:flutter/material.dart';

/// Static helper for displaying a [BTModal] over a barrier.
///
/// ## Usage:
/// ```dart
/// final result = await BTModalSheet.show<bool>(
///   context,
///   title: 'Delete account',
///   subtext: 'This action cannot be undone.',
///   primaryLabel: 'Delete',
///   onPrimary: () => Navigator.pop(context, true),
///   onSecondary: () => Navigator.pop(context, false),
/// );
/// ```
abstract final class BTModalSheet {
  /// Show a [BTModal] as a modal route.
  ///
  /// Returns whatever the caller passes to `Navigator.pop(context, ...)`
  /// from inside [onPrimary] / [onSecondary] / [onClose].
  static Future<T?> show<T>(
    BuildContext context, {
    required String title,
    String? subtext,
    bool hasClose = true,
    bool hasFooter = true,
    String primaryLabel = 'Confirm',
    bool hasSecondaryButton = true,
    String secondaryLabel = 'Cancel',
    bool hasCheckbox = false,
    String checkboxLabel = "Don't show again",
    bool dismissable = true,
    Widget? content,
    VoidCallback? onPrimary,
    VoidCallback? onSecondary,
    VoidCallback? onClose,
    ValueChanged<bool>? onCheckbox,
  }) {
    return showDialog<T>(
      context: context,
      barrierDismissible: dismissable,
      barrierColor: Colors.black54,
      builder: (ctx) => Center(
        child: BTModal(
          open: true,
          title: title,
          subtext: subtext,
          hasClose: hasClose,
          hasFooter: hasFooter,
          primaryLabel: primaryLabel,
          hasSecondaryButton: hasSecondaryButton,
          secondaryLabel: secondaryLabel,
          hasCheckbox: hasCheckbox,
          checkboxLabel: checkboxLabel,
          dismissable: dismissable,
          content: content,
          onPrimary: onPrimary ?? () => Navigator.of(ctx).pop(),
          onSecondary: onSecondary ?? () => Navigator.of(ctx).pop(),
          onClose: onClose ?? () => Navigator.of(ctx).pop(),
          onCheckbox: onCheckbox,
        ),
      ),
    );
  }
}

// Barrel for the BTModal organism.

export 'internal/modal_sheet.dart';
export 'modal.types.dart';
export 'modal.widget.dart';

// BTModal types — Figma source: M-Modal node 2124:2190.
//
// Mobile modals are full-width (328 px on the design canvas) with a
// vertically stacked footer (primary on top, secondary below) — there
// is no `BTModalSize` analogue for the web on mobile.

/// Width preset placeholder kept for cross-framework parity. On Flutter
/// the modal renders at the natural 328 dp width regardless of the
/// chosen size — this enum exists only so Vue / React / Flutter
/// `component.meta.yaml` shapes line up.
enum BTModalSize { sm, md, lg }

/// BTModal — centred dialog panel with header, optional content, footer.
///
/// Figma source: M-Modal node 2124:2190 (mobile).
///
/// The widget itself is the dialog *panel* — a fixed-width 328 dp card
/// with a white header and grey footer. It does NOT include a backdrop
/// or routing. Use [BTModalSheet.show] to display it as a modal route
/// with a barrier.
///
/// On mobile the footer stacks vertically: primary button is rendered
/// on top (full width), secondary below it (full width).
///
/// ## Usage:
/// ```dart
/// // Embedded panel (no backdrop):
/// BTModal(
///   open: true,
///   title: 'Confirm',
///   subtext: 'Are you sure?',
///   onPrimary: () { /* ... */ },
///   onSecondary: () { /* ... */ },
/// )
///
/// // Show as a modal route:
/// BTModalSheet.show(
///   context,
///   title: 'Confirm action',
///   subtext: 'This cannot be undone.',
///   onPrimary: () => Navigator.pop(context, true),
///   onSecondary: () => Navigator.pop(context, false),
/// );
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:btech_ui/src/components/atoms/button/button.widget.dart';
import 'package:btech_ui/src/components/atoms/checkbox/checkbox.widget.dart';
import 'package:flutter/material.dart';

class BTModal extends StatefulWidget {
  const BTModal({
    required this.open,
    required this.title,
    this.subtext,
    this.hasClose = true,
    this.hasFooter = true,
    this.primaryLabel = 'Confirm',
    this.hasSecondaryButton = true,
    this.secondaryLabel = 'Cancel',
    this.hasCheckbox = false,
    this.checkboxLabel = "Don't show again",
    this.dismissable = true,
    this.content,
    this.onPrimary,
    this.onSecondary,
    this.onClose,
    this.onCheckbox,
    super.key,
  });

  /// Whether the modal panel is visible. When false, an empty box renders.
  final bool open;

  /// Bold title shown at the top of the header.
  final String title;

  /// Optional supporting text shown below the title.
  final String? subtext;

  /// Show the X button in the top-right of the header.
  final bool hasClose;

  /// Show the footer section.
  final bool hasFooter;

  /// Label for the primary action button.
  final String primaryLabel;

  /// Show the secondary (cancel) button.
  final bool hasSecondaryButton;

  /// Label for the secondary action button.
  final String secondaryLabel;

  /// Show a checkbox in the footer.
  final bool hasCheckbox;

  /// Label rendered next to the footer checkbox.
  final String checkboxLabel;

  /// Click on backdrop closes the modal — used by [BTModalSheet.show]
  /// to set `barrierDismissible`. Has no effect on the panel itself.
  final bool dismissable;

  /// Optional widget rendered inside the white header section, below
  /// the title row.
  final Widget? content;

  /// Called when the primary action button is pressed.
  final VoidCallback? onPrimary;

  /// Called when the secondary action button is pressed.
  final VoidCallback? onSecondary;

  /// Called when the X close button is pressed.
  final VoidCallback? onClose;

  /// Called when the footer checkbox is toggled.
  final ValueChanged<bool>? onCheckbox;

  @override
  State<BTModal> createState() => _BTModalState();
}

class _BTModalState extends State<BTModal> {
  bool _checked = false;

  @override
  Widget build(BuildContext context) {
    if (!widget.open) return const SizedBox.shrink();

    final colors = context.btColor;
    final radius = context.btRadius;

    return Material(
      color: Colors.transparent,
      child: Container(
        width: 328.0,
        constraints: BoxConstraints(maxHeight: 600.0),
        decoration: BoxDecoration(
          color: colors.bg.primary,
          borderRadius: BorderRadius.circular(radius.md),
          boxShadow: const [
            BoxShadow(
              color: Color(0x29000000),
              blurRadius: 32,
              offset: Offset(0, 16),
            ),
          ],
        ),
        clipBehavior: Clip.antiAlias,
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            _buildHeader(context),
            if (widget.content != null)
              Padding(
                padding: EdgeInsets.fromLTRB(16.0, 0, 16.0, 16.0),
                child: widget.content,
              ),
            if (widget.hasFooter) _buildFooter(context),
          ],
        ),
      ),
    );
  }

  Widget _buildHeader(BuildContext context) {
    final colors = context.btColor;
    return Padding(
      padding: EdgeInsets.all(16.0),
      child: Stack(
        children: [
          Padding(
            padding: EdgeInsetsDirectional.only(end: 32.0),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              mainAxisSize: MainAxisSize.min,
              children: [
                Text(
                  widget.title,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 18.0,
                    fontWeight: FontWeight.w700,
                    height: 1.4,
                    color: colors.text.primary,
                  ),
                ),
                if (widget.subtext != null) ...[
                  SizedBox(height: 4.0),
                  Text(
                    widget.subtext!,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 14.0,
                      fontWeight: FontWeight.w500,
                      height: 1.4,
                      color: colors.text.secondary,
                    ),
                  ),
                ],
              ],
            ),
          ),
          if (widget.hasClose)
            PositionedDirectional(
              top: 0,
              end: 0,
              child: GestureDetector(
                onTap: widget.onClose,
                behavior: HitTestBehavior.opaque,
                child: SizedBox(
                  width: 24.0,
                  height: 24.0,
                  child: Icon(
                    Icons.close,
                    size: 16,
                    color: colors.text.secondary,
                  ),
                ),
              ),
            ),
        ],
      ),
    );
  }

  Widget _buildFooter(BuildContext context) {
    final colors = context.btColor;
    return Container(
      width: double.infinity,
      decoration: BoxDecoration(
        color: colors.bg.subtle,
        border: Border(
          top: BorderSide(color: colors.border.primary),
        ),
      ),
      padding: EdgeInsets.fromLTRB(16.0, 12.0, 16.0, 12.0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        mainAxisSize: MainAxisSize.min,
        children: [
          if (widget.hasCheckbox)
            Padding(
              padding: EdgeInsets.only(bottom: 12.0),
              child: BTCheckbox(
                checked: _checked,
                label: widget.checkboxLabel,
                onChanged: (v) {
                  setState(() => _checked = v);
                  widget.onCheckbox?.call(v);
                },
              ),
            ),
          // Mobile stacks: primary on top (full width), secondary below.
          SizedBox(
            width: double.infinity,
            child: BTButton(
              label: widget.primaryLabel,
              onPressed: widget.onPrimary,
            ),
          ),
          if (widget.hasSecondaryButton) ...[
            SizedBox(height: 8.0),
            SizedBox(
              width: double.infinity,
              child: BTButton(
                label: widget.secondaryLabel,
                variant: BTButtonVariant.secondaryLight,
                onPressed: widget.onSecondary,
              ),
            ),
          ],
        ],
      ),
    );
  }
}
